import{_ as a,j as h,o as n,v as t}from"./chunks/framework.gVsiwu-7.js";const i=JSON.parse('{"title":"Tìm hiểu lịch sử và mục đích của kafka","description":"","frontmatter":{"footer":true,"title":"Tìm hiểu lịch sử và mục đích của kafka","authors":["lethanh"],"date":"2024-04-24T00:00:00.000Z","outline":"deep","draft":true,"group":"2.1 Kafka"},"headers":[{"level":2,"title":"Kafka là gì ?","slug":"kafka-la-gi","link":"#kafka-la-gi","children":[]},{"level":2,"title":"Đặc điểm của Apache kafka:","slug":"đac-điem-cua-apache-kafka","link":"#đac-điem-cua-apache-kafka","children":[]},{"level":2,"title":"Vì sao là kafka","slug":"vi-sao-la-kafka","link":"#vi-sao-la-kafka","children":[]}],"relativePath":"study/thanhlv-study-2024/2024-04-25-tim-hieu-lich-su-va-muc-dich-cua-kafka.md","filePath":"study/thanhlv-study-2024/2024-04-25-tim-hieu-lich-su-va-muc-dich-cua-kafka.md","lastUpdated":1715764363000}'),c={name:"study/thanhlv-study-2024/2024-04-25-tim-hieu-lich-su-va-muc-dich-cua-kafka.md"},l=[t('<h1 id="tim-hieu-lich-su-va-muc-đich-cua-kafka" tabindex="-1">Tìm hiểu lịch sử và mục đích của kafka <a class="header-anchor" href="#tim-hieu-lich-su-va-muc-đich-cua-kafka" aria-label="Permalink to &quot;Tìm hiểu lịch sử và mục đích của kafka&quot;">​</a></h1><p>Trong bài viết này, chúng ta sẽ cùng nhau bước vào hành trình khám phá Kafka, một công nghệ đã và đang làm thay đổi cách thức xử lý dữ liệu trong thế giới số.</p><p>Từ những đặc điểm đến những mục tiêu chiến lược mà Kafka hướng đến, chúng ta sẽ cùng nhau tìm hiểu sâu hơn về công nghệ này, làm sáng tỏ những ưu điểm và lý do tại sao Kafka lại trở thành một phần không thể thiếu trong hệ sinh thái dữ liệu hiện đại.</p><nav class="table-of-contents"><ul><li><a href="#kafka-la-gi">Kafka là gì ?</a></li><li><a href="#đac-điem-cua-apache-kafka">Đặc điểm của Apache kafka:</a></li><li><a href="#vi-sao-la-kafka">Vì sao là kafka</a></li></ul></nav><h2 id="kafka-la-gi" tabindex="-1">Kafka là gì ? <a class="header-anchor" href="#kafka-la-gi" aria-label="Permalink to &quot;Kafka là gì ?&quot;">​</a></h2><ul><li>Apache Kafka là một <a href="./2024-04-21-event-stream-va-event-stream-platform-la-gi.html">Event stream platform</a> được phát triển bởi <a href="https://www.linkedin.com/" target="_blank" rel="noreferrer">LinkedIn</a> và quyên góp cho apache và phát hành thành mã nguồn mở (Open-source) vào năm 2011.</li><li>Apache Kafka được viết bằng <code>Scala</code> và <code>Java</code>. Dự án này nhằm mục đích cung cấp một nền tảng có khả năng xử lý dữ liệu với lượng thông tin lớn, độ trễ thấp, phù hợp cho việc xử lý dữ liệu <code>real-time</code></li><li>Ở high level, Kafka là một hệ thống phân tán servers và clients. Servers được gọi là <strong>brokers</strong> và client được chia làm 2 là <strong>record producers sending</strong> và <strong>consumer clients read records</strong></li></ul><h2 id="đac-điem-cua-apache-kafka" tabindex="-1">Đặc điểm của Apache kafka: <a class="header-anchor" href="#đac-điem-cua-apache-kafka" aria-label="Permalink to &quot;Đặc điểm của Apache kafka:&quot;">​</a></h2><ul><li><p><strong>Distributed System(Hệ thống phân tán)</strong>: Apache Kafka là một hệ thống phân tán được thiết kế chạy trên nhiều máy chủ, đảm bảo tính sẵn sàng cao và khả năng chịu lỗi.</p></li><li><p><strong>Publish-Subscribe Model(Mô hình Publish-Subscribe)</strong>: Kafka flow theo mô hình Publish-Subscribe, nơi các publish phát các messages đến topics và consumers subscribe các topics để đọc messages.</p></li><li><p><strong>High Throughput</strong>: Có thể hiểu đơn giản là Kafka có khả năng xử lý một lượng lớn dữ liệu, làm cho nó phù hợp với big data.</p></li><li><p><strong>Scalability(Khả năng mở rộng)</strong> : Kafka có thể mở rộng dễ dàng mà không cần ngừng hoạt động, Cụm Kafka có thể tăng một node hoặc giảm một Node theo nhu cầu một cách dễ dàng.</p></li><li><p><strong>Durability and Reliability(Độ bền và tin cậy cao), PERMANENT STORAGE</strong>: Kafka chạy hệ thống phân tán, dữ liệu được lưu trữ an toàn trong một cụm phân tán, đảm bảo sẽ lưu sẽ an toàn và không bị lỗi.</p></li></ul><h2 id="vi-sao-la-kafka" tabindex="-1">Vì sao là kafka <a class="header-anchor" href="#vi-sao-la-kafka" aria-label="Permalink to &quot;Vì sao là kafka&quot;">​</a></h2>',9)];const e=a(c,[["render",function(a,t,i,c,e,s){return n(),h("div",null,l)}]]);export{i as __pageData,e as default};
